mapper.select:
SELECT COUNT(*) FROM mcpeventmng.NMCP_EVENT_BOARD_BAS WHERE LIST_VIEW_YN = 'Y' AND SBST_CTG = #{eventBranch}
AND UPPER(fnHTMLtoTEXT(NTCART_SUBJECT)) LIKE '%' || UPPER(#{searchValue}) || '%' ESCAPE '!'
AND ((TO_CHAR(CURRENT_TIMESTAMP,'YYYYMMDDHH24') BETWEEN TO_CHAR(EVENT_START_DT,'YYYYMMDD') || START_HOUR AND TO_CHAR(EVENT_END_DT,'YYYYMMDD') || END_HOUR ) OR (TO_CHAR(CURRENT_TIMESTAMP,'YYYYMMDDHH24') BETWEEN TO_CHAR(EVENT_START_DT_SEC,'YYYYMMDD') || START_HOUR_SEC AND TO_CHAR(EVENT_END_DT_SEC,'YYYYMMDD') || END_HOUR_SEC ))

SELECT a.NTCART_SEQ, a.NTCART_SUBJECT, a.LIST_VIEW_YN, a.EVENT_VIEW_YN, a.IMG_DESC, a.EVENT_START_DT, a.EVENT_END_DT, CASE WHEN TO_CHAR(CURRENT_TIMESTAMP,'YYYYMMDDHH24') BETWEEN TO_CHAR(a.EVENT_START_DT,'YYYYMMDD') || a.START_HOUR AND TO_CHAR(a.EVENT_END_DT,'YYYYMMDD') || a.END_HOUR THEN TO_CHAR(a.EVENT_START_DT,'YYYY.MM.DD') ELSE TO_CHAR(a.EVENT_START_DT_SEC,'YYYY.MM.DD') END AS COM_EVENT_START_DT, CASE WHEN TO_CHAR(CURRENT_TIMESTAMP,'YYYYMMDDHH24') BETWEEN TO_CHAR(a.EVENT_START_DT,'YYYYMMDD') || a.START_HOUR AND TO_CHAR(a.EVENT_END_DT,'YYYYMMDD') || a.END_HOUR THEN TO_CHAR(a.EVENT_END_DT,'YYYY.MM.DD') ELSE TO_CHAR(a.EVENT_END_DT_SEC,'YYYY.MM.DD') END AS COM_EVENT_END_DT, CASE WHEN TO_CHAR(CURRENT_TIMESTAMP,'YYYYMMDDHH24') BETWEEN TO_CHAR(a.EVENT_START_DT,'YYYYMMDD') || a.START_HOUR AND TO_CHAR(a.EVENT_END_DT,'YYYYMMDD') || a.END_HOUR THEN a.LIST_IMG ELSE a.LIST_IMG_SEC END AS LIST_IMG, a.EVENT_START_DT AS EVENT_START_DT_B, a.EVENT_END_DT AS EVENT_END_DT_B, a.START_HOUR, a.END_HOUR, a.NTCART_SBST, a.NTCART_WRITER, a.NTCART_WRITE_DT, a.NTCART_HIT_CNT, a.CRET_ID, a.AMD_ID, a.CRET_DT, a.AMD_DT, a.SBST_CTG, a.LINK_TARGET, a.LINK_URL_ADR, a.LINK_TARGET_MO, a.LINK_URL_ADR_MO, a.EVENT_URL_ADR, a.PLN_SMALL_TITLE, a.PLN_CONTENT, a.SNS_SBST, a.NTCART_SBST2, a.PLN_CONTENT2, DATE_PART('day',a.EVENT_END_DT-CURRENT_TIMESTAMP) as D_Day, (SELECT MAX(PWNR_SEQ) FROM mcpeventmng.NMCP_PWNR_BOARD_BAS WHERE NTCART_SEQ = a.NTCART_SEQ) as WINNER_YN, CASE SIGN(DATE_PART('day',a.EVENT_END_DT-CURRENT_TIMESTAMP)) WHEN -1 THEN 0 ELSE 1 END AS ABS_DAY, a.MOBILE_LIST_IMG_NM, a.EVENT_CATEGORY FROM mcpeventmng.NMCP_EVENT_BOARD_BAS a WHERE a.LIST_VIEW_YN = 'Y' AND SBST_CTG = #{eventBranch}
AND UPPER(fnHTMLtoTEXT(a.NTCART_SUBJECT)) LIKE '%' || UPPER(#{searchValue}) || '%' ESCAPE '!'
AND ((TO_CHAR(CURRENT_TIMESTAMP,'YYYYMMDDHH24') BETWEEN TO_CHAR(a.EVENT_START_DT,'YYYYMMDD') || a.START_HOUR AND TO_CHAR(a.EVENT_END_DT,'YYYYMMDD') || a.END_HOUR ) OR (TO_CHAR(CURRENT_TIMESTAMP,'YYYYMMDDHH24') BETWEEN TO_CHAR(a.EVENT_START_DT_SEC,'YYYYMMDD') || a.START_HOUR_SEC AND TO_CHAR(a.EVENT_END_DT_SEC,'YYYYMMDD') || a.END_HOUR_SEC )) ORDER BY EVENT_ORDER, CRET_DT DESC

SELECT COUNT(NTCART_SEQ) FROM mcpeventmng.NMCP_EVENT_BOARD_BAS WHERE LIST_VIEW_YN = 'Y' AND SBST_CTG = #{eventBranch}
AND UPPER(fnHTMLtoTEXT(NTCART_SUBJECT)) LIKE '%' || UPPER(#{searchValue}) || '%' ESCAPE '!'
AND TO_CHAR(CURRENT_DATE, 'YYYYMMDD') > TO_CHAR(EVENT_END_DT,'YYYYMMDD')

SELECT ROW_NUMBER() OVER(ORDER BY NTCART_WRITE_DT) AS BOARD_NUM, a.NTCART_SEQ, a.NTCART_SUBJECT, a.LIST_VIEW_YN, a.EVENT_VIEW_YN, a.LIST_IMG, a.IMG_DESC, a.EVENT_START_DT, a.EVENT_END_DT, TO_CHAR(a.EVENT_START_DT,'YYYY.MM.DD') AS COM_EVENT_START_DT, TO_CHAR(a.EVENT_END_DT,'YYYY.MM.DD') AS COM_EVENT_END_DT, a.START_HOUR, a.END_HOUR, a.NTCART_SBST, a.NTCART_WRITER, a.NTCART_WRITE_DT, a.NTCART_HIT_CNT, a.CRET_ID, a.AMD_ID, a.CRET_DT, TO_CHAR(a.CRET_DT,'YYYY.MM.DD') AS COM_CRET_DT, a.AMD_DT, a.SBST_CTG, a.LINK_TARGET, a.LINK_URL_ADR, a.LINK_URL_ADR_MO, a.LINK_TARGET_MO, a.EVENT_URL_ADR, a.PLN_SMALL_TITLE, a.PLN_CONTENT, a.SNS_SBST, a.NTCART_SBST2, a.PLN_CONTENT2, DATE_PART('day',a.EVENT_END_DT-CURRENT_TIMESTAMP) as D_Day, (SELECT MAX(PWNR_SEQ) FROM mcpeventmng.NMCP_PWNR_BOARD_BAS WHERE NTCART_SEQ = a.NTCART_SEQ AND STAT_VAL = 'Y') as WINNER_YN, CASE SIGN(DATE_PART('day',a.EVENT_END_DT-CURRENT_TIMESTAMP)) WHEN -1 THEN 0 ELSE 1 END AS ABS_DAY, a.MOBILE_LIST_IMG_NM FROM mcpeventmng.NMCP_EVENT_BOARD_BAS a WHERE a.LIST_VIEW_YN = 'Y' AND SBST_CTG = #{eventBranch}
AND UPPER(fnHTMLtoTEXT(a.NTCART_SUBJECT)) LIKE '%' || UPPER(#{searchValue}) || '%' ESCAPE '!'
AND TO_CHAR(CURRENT_DATE, 'YYYYMMDD') > TO_CHAR(a.EVENT_END_DT,'YYYYMMDD') ORDER BY EVENT_ORDER, CRET_DT DESC

SELECT aa.BOARD_NUM , aa.NTCART_SEQ , aa.NTCART_SUBJECT , aa.LIST_VIEW_YN , aa.EVENT_VIEW_YN , aa.LIST_IMG , aa.IMG_DESC , aa.EVENT_START_DT , aa.EVENT_END_DT , aa.NTCART_WRITER , aa.NTCART_WRITE_DT , aa.NTCART_HIT_CNT , aa.CRET_ID , aa.AMD_ID , aa.CRET_DT , aa.AMD_DT , aa.SBST_CTG , aa.LINK_TARGET , aa.LINK_URL_ADR , aa.LINK_TARGET_MO , aa.LINK_URL_ADR_MO , aa.EVENT_URL_ADR , aa.PLN_SMALL_TITLE , aa.SNS_SBST , aa.EVENTJOIN_CD
, aa.NTCART_SBST2 , aa.PLN_CONTENT2
, aa.NTCART_SBST , aa.PLN_CONTENT
, aa.DDAY , aa.WINNER_YN , aa.PRE_SEQ , aa.PRE_SUBJECT , aa.PRE_DT , aa.NEXT_SEQ , aa.NEXT_SUBJECT , aa.NEXT_DT , aa.EVENT_HEADER_TITLE , aa.EVENT_KEYWORD , aa.EVENT_TITLE ,aa.EVENT_DESCRIPTION FROM ( SELECT ROW_NUMBER() OVER(ORDER BY a.NTCART_WRITE_DT) AS BOARD_NUM, a.NTCART_SEQ, a.NTCART_SUBJECT, a.LIST_VIEW_YN, a.EVENT_VIEW_YN, a.IMG_DESC ,CASE WHEN TO_CHAR(CURRENT_TIMESTAMP,'YYYYMMDDHH24') BETWEEN TO_CHAR(a.EVENT_START_DT,'YYYYMMDD') || a.START_HOUR AND TO_CHAR(a.EVENT_END_DT,'YYYYMMDD') || a.END_HOUR THEN TO_CHAR(a.EVENT_START_DT,'YYYY.MM.DD') ELSE TO_CHAR(a.EVENT_START_DT_SEC,'YYYY.MM.DD') END AS EVENT_START_DT ,CASE WHEN TO_CHAR(CURRENT_TIMESTAMP,'YYYYMMDDHH24') BETWEEN TO_CHAR(a.EVENT_START_DT,'YYYYMMDD') || a.START_HOUR AND TO_CHAR(a.EVENT_END_DT,'YYYYMMDD') || a.END_HOUR THEN TO_CHAR(a.EVENT_END_DT,'YYYY.MM.DD') ELSE TO_CHAR(a.EVENT_END_DT_SEC,'YYYY.MM.DD') END AS EVENT_END_DT ,CASE WHEN TO_CHAR(CURRENT_TIMESTAMP,'YYYYMMDDHH24') BETWEEN TO_CHAR(a.EVENT_START_DT,'YYYYMMDD') || a.START_HOUR AND TO_CHAR(a.EVENT_END_DT,'YYYYMMDD') || a.END_HOUR THEN LIST_IMG ELSE LIST_IMG_SEC END AS LIST_IMG ,CASE WHEN TO_CHAR(CURRENT_TIMESTAMP,'YYYYMMDDHH24') BETWEEN TO_CHAR(a.EVENT_START_DT,'YYYYMMDD') || a.START_HOUR AND TO_CHAR(a.EVENT_END_DT,'YYYYMMDD') || a.END_HOUR THEN NTCART_SBST ELSE NTCART_SBST_SEC END AS NTCART_SBST ,CASE WHEN TO_CHAR(CURRENT_TIMESTAMP,'YYYYMMDDHH24') BETWEEN TO_CHAR(a.EVENT_START_DT,'YYYYMMDD') || a.START_HOUR AND TO_CHAR(a.EVENT_END_DT,'YYYYMMDD') || a.END_HOUR THEN NTCART_SBST2 ELSE NTCART_SBST2_SEC END AS NTCART_SBST2, a.NTCART_WRITER, a.NTCART_WRITE_DT, a.NTCART_HIT_CNT, a.CRET_ID, a.AMD_ID, a.CRET_DT, a.AMD_DT, a.SBST_CTG, a.LINK_TARGET, a.LINK_URL_ADR, a.LINK_TARGET_MO, a.LINK_URL_ADR_MO, a.EVENT_URL_ADR, a.PLN_SMALL_TITLE, a.PLN_CONTENT, a.SNS_SBST, a.EVENTJOIN_CD, a.PLN_CONTENT2, DATE_PART('day',a.EVENT_END_DT-CURRENT_TIMESTAMP) as dDay, (SELECT MAX(PWNR_SEQ) FROM mcpeventmng.NMCP_PWNR_BOARD_BAS WHERE NTCART_SEQ = a.NTCART_SEQ AND STAT_VAL = 'Y') as WINNER_YN, lead(a.NTCART_SEQ,1) over (order by a.EVENT_ORDER, a.NTCART_WRITE_DT DESC) NEXT_SEQ, lead(a.NTCART_SUBJECT,1,'다음글이 없습니다.') over (order by a.EVENT_ORDER, a.NTCART_WRITE_DT DESC) NEXT_SUBJECT, lead(a.CRET_DT,1) over (order by a.EVENT_ORDER, a.NTCART_WRITE_DT DESC) NEXT_DT, lag(a.NTCART_SEQ,1) over (order by a.EVENT_ORDER, a.NTCART_WRITE_DT DESC) PRE_SEQ, lag(a.NTCART_SUBJECT,1,'이전글이 없습니다.') over (order by a.EVENT_ORDER, a.NTCART_WRITE_DT DESC) PRE_SUBJECT, lag(a.CRET_DT,1) over (order by a.EVENT_ORDER, a.NTCART_WRITE_DT DESC) PRE_DT, a.EVENT_HEADER_TITLE, a.EVENT_KEYWORD, a.EVENT_TITLE, a.EVENT_DESCRIPTION FROM mcpeventmng.NMCP_EVENT_BOARD_BAS a WHERE a.EVENT_VIEW_YN = 'Y'
AND a.SBST_CTG = #{sbstCtg}
AND a.LIST_VIEW_YN = (SELECT LIST_VIEW_YN FROM mcpeventmng.NMCP_EVENT_BOARD_BAS WHERE NTCART_SEQ = #{ntcartSeq})
AND UPPER(fnHTMLtoTEXT(a.NTCART_SUBJECT)) LIKE '%' || UPPER(#{searchValue}) || '%' ESCAPE '!'
) aa WHERE aa.NTCART_SEQ = #{ntcartSeq}

SELECT COUNT(*) FROM mcpeventmng.NMCP_EVENT_BOARD_BAS WHERE LIST_VIEW_YN = 'Y' AND SBST_CTG = #{eventBranch}
AND UPPER(fnHTMLtoTEXT(NTCART_SUBJECT)) LIKE '%' || UPPER(#{searchValue}) || '%' ESCAPE '!'
AND (#{adminEventDate} BETWEEN TO_CHAR(EVENT_START_DT,'YYYYMMDD') || START_HOUR AND TO_CHAR(EVENT_END_DT,'YYYYMMDD') || END_HOUR ) OR (#{adminEventDate} BETWEEN TO_CHAR(EVENT_START_DT_SEC,'YYYYMMDD') || START_HOUR_SEC AND TO_CHAR(EVENT_END_DT_SEC,'YYYYMMDD') || END_HOUR_SEC )

SELECT a.NTCART_SEQ, a.NTCART_SUBJECT, a.LIST_VIEW_YN, a.EVENT_VIEW_YN, a.IMG_DESC, a.EVENT_START_DT, a.EVENT_END_DT, CASE WHEN #{adminEventDate} BETWEEN TO_CHAR(a.EVENT_START_DT,'YYYYMMDD') || a.START_HOUR AND TO_CHAR(a.EVENT_END_DT,'YYYYMMDD') || a.END_HOUR THEN TO_CHAR(a.EVENT_START_DT,'YYYY.MM.DD') ELSE TO_CHAR(a.EVENT_START_DT_SEC,'YYYY.MM.DD') END AS COM_EVENT_START_DT, CASE WHEN #{adminEventDate} BETWEEN TO_CHAR(a.EVENT_START_DT,'YYYYMMDD') || a.START_HOUR AND TO_CHAR(a.EVENT_END_DT,'YYYYMMDD') || a.END_HOUR THEN TO_CHAR(a.EVENT_END_DT,'YYYY.MM.DD') ELSE TO_CHAR(a.EVENT_END_DT_SEC,'YYYY.MM.DD') END AS COM_EVENT_END_DT, CASE WHEN #{adminEventDate} BETWEEN TO_CHAR(a.EVENT_START_DT,'YYYYMMDD') || a.START_HOUR AND TO_CHAR(a.EVENT_END_DT,'YYYYMMDD') || a.END_HOUR THEN a.LIST_IMG ELSE a.LIST_IMG_SEC END AS LIST_IMG, a.EVENT_START_DT AS EVENT_START_DT_B, a.EVENT_END_DT AS EVENT_END_DT_B, a.START_HOUR, a.END_HOUR, a.NTCART_SBST, a.NTCART_WRITER, a.NTCART_WRITE_DT, a.NTCART_HIT_CNT, a.CRET_ID, a.AMD_ID, a.CRET_DT, a.AMD_DT, a.SBST_CTG, a.LINK_TARGET, a.LINK_URL_ADR, a.LINK_TARGET_MO, a.LINK_URL_ADR_MO, a.EVENT_URL_ADR, a.PLN_SMALL_TITLE, a.PLN_CONTENT, a.SNS_SBST, a.NTCART_SBST2, a.PLN_CONTENT2, (SELECT MAX(PWNR_SEQ) FROM mcpeventmng.NMCP_PWNR_BOARD_BAS WHERE NTCART_SEQ = a.NTCART_SEQ) as WINNER_YN, a.MOBILE_LIST_IMG_NM, a.EVENT_CATEGORY FROM mcpeventmng.NMCP_EVENT_BOARD_BAS a WHERE a.LIST_VIEW_YN = 'Y' AND SBST_CTG = #{eventBranch}
AND UPPER(fnHTMLtoTEXT(a.NTCART_SUBJECT)) LIKE '%' || UPPER(#{searchValue}) || '%' ESCAPE '!'
AND (#{adminEventDate} BETWEEN TO_CHAR(a.EVENT_START_DT,'YYYYMMDD') || a.START_HOUR AND TO_CHAR(a.EVENT_END_DT,'YYYYMMDD') || a.END_HOUR ) OR (#{adminEventDate} BETWEEN TO_CHAR(a.EVENT_START_DT_SEC,'YYYYMMDD') || a.START_HOUR_SEC AND TO_CHAR(a.EVENT_END_DT_SEC,'YYYYMMDD') || a.END_HOUR_SEC ) ORDER BY EVENT_ORDER, CRET_DT DESC

SELECT aa.BOARD_NUM , aa.NTCART_SEQ , aa.NTCART_SUBJECT , aa.LIST_VIEW_YN , aa.EVENT_VIEW_YN , aa.LIST_IMG , aa.IMG_DESC , aa.EVENT_START_DT , aa.EVENT_END_DT , aa.NTCART_WRITER , aa.NTCART_WRITE_DT , aa.NTCART_HIT_CNT , aa.CRET_ID , aa.AMD_ID , aa.CRET_DT , aa.AMD_DT , aa.SBST_CTG , aa.LINK_TARGET , aa.LINK_URL_ADR , aa.LINK_TARGET_MO , aa.LINK_URL_ADR_MO , aa.EVENT_URL_ADR , aa.PLN_SMALL_TITLE , aa.SNS_SBST , aa.EVENTJOIN_CD
, aa.NTCART_SBST2 , aa.PLN_CONTENT2
, aa.NTCART_SBST , aa.PLN_CONTENT
, aa.DDAY , aa.WINNER_YN , aa.PRE_SEQ , aa.PRE_SUBJECT , aa.PRE_DT , aa.NEXT_SEQ , aa.NEXT_SUBJECT , aa.NEXT_DT , aa.EVENT_HEADER_TITLE FROM ( SELECT ROW_NUMBER() OVER(ORDER BY a.NTCART_WRITE_DT) AS BOARD_NUM, a.NTCART_SEQ, a.NTCART_SUBJECT, a.LIST_VIEW_YN, a.EVENT_VIEW_YN, a.IMG_DESC ,CASE WHEN #{adminEventDate} BETWEEN TO_CHAR(a.EVENT_START_DT,'YYYYMMDD') || a.START_HOUR AND TO_CHAR(a.EVENT_END_DT,'YYYYMMDD') || a.END_HOUR THEN TO_CHAR(a.EVENT_START_DT,'YYYY.MM.DD') ELSE TO_CHAR(a.EVENT_START_DT_SEC,'YYYY.MM.DD') END AS EVENT_START_DT ,CASE WHEN #{adminEventDate} BETWEEN TO_CHAR(a.EVENT_START_DT,'YYYYMMDD') || a.START_HOUR AND TO_CHAR(a.EVENT_END_DT,'YYYYMMDD') || a.END_HOUR THEN TO_CHAR(a.EVENT_END_DT,'YYYY.MM.DD') ELSE TO_CHAR(a.EVENT_END_DT_SEC,'YYYY.MM.DD') END AS EVENT_END_DT ,CASE WHEN #{adminEventDate} BETWEEN TO_CHAR(a.EVENT_START_DT,'YYYYMMDD') || a.START_HOUR AND TO_CHAR(a.EVENT_END_DT,'YYYYMMDD') || a.END_HOUR THEN LIST_IMG ELSE LIST_IMG_SEC END AS LIST_IMG ,CASE WHEN #{adminEventDate} BETWEEN TO_CHAR(a.EVENT_START_DT,'YYYYMMDD') || a.START_HOUR AND TO_CHAR(a.EVENT_END_DT,'YYYYMMDD') || a.END_HOUR THEN NTCART_SBST ELSE NTCART_SBST_SEC END AS NTCART_SBST ,CASE WHEN #{adminEventDate} BETWEEN TO_CHAR(a.EVENT_START_DT,'YYYYMMDD') || a.START_HOUR AND TO_CHAR(a.EVENT_END_DT,'YYYYMMDD') || a.END_HOUR THEN NTCART_SBST2 ELSE NTCART_SBST2_SEC END AS NTCART_SBST2, a.NTCART_WRITER, a.NTCART_WRITE_DT, a.NTCART_HIT_CNT, a.CRET_ID, a.AMD_ID, a.CRET_DT, a.AMD_DT, a.SBST_CTG, a.LINK_TARGET, a.LINK_URL_ADR, a.LINK_TARGET_MO, a.LINK_URL_ADR_MO, a.EVENT_URL_ADR, a.PLN_SMALL_TITLE, a.PLN_CONTENT, a.SNS_SBST, a.EVENTJOIN_CD, a.PLN_CONTENT2, DATE_PART('day',a.EVENT_END_DT-CURRENT_TIMESTAMP) as dDay, (SELECT MAX(PWNR_SEQ) FROM mcpeventmng.NMCP_PWNR_BOARD_BAS WHERE NTCART_SEQ = a.NTCART_SEQ AND STAT_VAL = 'Y') as WINNER_YN, lead(a.NTCART_SEQ,1) over (order by a.EVENT_ORDER, a.NTCART_WRITE_DT DESC) NEXT_SEQ, lead(a.NTCART_SUBJECT,1,'다음글이 없습니다.') over (order by a.EVENT_ORDER, a.NTCART_WRITE_DT DESC) NEXT_SUBJECT, lead(a.CRET_DT,1) over (order by a.EVENT_ORDER, a.NTCART_WRITE_DT DESC) NEXT_DT, lag(a.NTCART_SEQ,1) over (order by a.EVENT_ORDER, a.NTCART_WRITE_DT DESC) PRE_SEQ, lag(a.NTCART_SUBJECT,1,'이전글이 없습니다.') over (order by a.EVENT_ORDER, a.NTCART_WRITE_DT DESC) PRE_SUBJECT, lag(a.CRET_DT,1) over (order by a.EVENT_ORDER, a.NTCART_WRITE_DT DESC) PRE_DT, a.EVENT_HEADER_TITLE FROM mcpeventmng.NMCP_EVENT_BOARD_BAS a WHERE a.EVENT_VIEW_YN = 'Y'
AND a.SBST_CTG = #{sbstCtg}
AND a.LIST_VIEW_YN = (SELECT LIST_VIEW_YN FROM mcpeventmng.NMCP_EVENT_BOARD_BAS WHERE NTCART_SEQ = #{ntcartSeq})
AND UPPER(fnHTMLtoTEXT(a.NTCART_SUBJECT)) LIKE '%' || UPPER(#{searchValue}) || '%' ESCAPE '!'
) aa WHERE aa.NTCART_SEQ = #{ntcartSeq}
